#include <stdio.h>
#include <string.h>
void reverse(char *l, char *r) {
    if (l >= r) return;
    char t = *l; *l = *r; *r = t;
    reverse(l + 1, r - 1);
}
int main() {
    char str[100];
    if (scanf("%99s", str) == 1) {
        reverse(str, str + strlen(str) - 1);
        printf("%s", str);
    }
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
struct Node { int data; struct Node* next; };
struct Node* top = NULL;
void push(int val) {
    struct Node* temp = malloc(sizeof(struct Node));
    temp->data = val; temp->next = top; top = temp;
}
int find(int val) {
    struct Node* curr = top; int pos = 1;
    while(curr) { if(curr->data == val) return pos; curr = curr->next; pos++; }
    return -1;
}
int main() {
    int n, target;
    if(scanf("%d", &n) == 1) {
        for(int i=0; i<n; i++) { int v; scanf("%d", &v); push(v); }
        scanf("%d", &target);
        printf("%d", find(target));
    }
    return 0;
}

#include <stdio.h>
int add(int a, int b) {
    while (b != 0) {
        int carry = a & b;
        a = a ^ b;
        b = (unsigned int)carry << 1;
    }
    return a;
}
int main() {
    int num1, num2;
    if (scanf("%d %d", &num1, &num2) == 2) printf("%d", add(num1, num2));
    return 0;
}

#include <stdio.h>
int subtract(int a, int b) {
    while (b != 0) {
        int borrow = (~a) & b;
        a = a ^ b;
        b = (unsigned int)borrow << 1;
    }
    return a;
}
int main() {
    int num1, num2;
    if (scanf("%d %d", &num1, &num2) == 2) printf("%d", subtract(num1, num2));
    return 0;
}

