#include <stdio.h>
int countSetBits(int n) {
    int count = 0;
    while (n) {
        n &= (n - 1);
        count++;
    }
    return count;
}
int main() {
    int num;
    if (scanf("%d", &num) == 1) printf("%d", countSetBits(num));
    return 0;
}

