#include <stdio.h>
unsigned char swapNibbles(unsigned char x) {
    return ( (x & 0x0F) << 4 | (x & 0xF0) >> 4 );
}
int main() {
    unsigned int num;
    if (scanf("%u", &num) == 1) {
        printf("%u", swapNibbles((unsigned char)num));
    }
    return 0;
}

